// NewToolsCallHandler creates a JSON-RPC handler which calls the
// "mcp_assistant" service "tools/call" endpoint.
func NewToolsCallHandler(
	endpoint goa.Endpoint,
	mux goahttp.Muxer,
	decoder func(*http.Request) goahttp.Decoder,
	encoder func(context.Context, http.ResponseWriter) goahttp.Encoder,
	errhandler func(context.Context, http.ResponseWriter, error),
) func(context.Context, *http.Request, *jsonrpc.RawRequest, http.ResponseWriter) error {
	return func(ctx context.Context, r *http.Request, req *jsonrpc.RawRequest, w http.ResponseWriter) error {
		ctx = context.WithValue(ctx, goa.MethodKey, "tools/call")
		ctx = context.WithValue(ctx, goa.ServiceKey, "mcp_assistant")
		// Initialize SSE stream lazily so endpoint failures can still choose the correct HTTP status.
		// The raw streamable-HTTP GET listener is the exception: it must establish
		// the SSE connection before the first domain event so clients can observe
		// readiness before publishing notifications.
		strm := &ToolsCallServerStream{
			w:         w,
			r:         r,
			encoder:   encoder,
			requestID: req.ID,
		}
		if r.Method == http.MethodGet && req.Method == "events/stream" {
			if err := strm.open(); err != nil {
				return err
			}
		}
		decodeParams := DecodeToolsCallRequest(mux, decoder)
		params, err := decodeParams(r, req)
		if err != nil {
			// Send error via the normal JSON-RPC SSE message channel.
			if req.ID != nil && req.ID != "" {
				strm.SendError(ctx, jsonrpc.IDToString(req.ID), err)
			}
			return nil
		}
		v := &mcpassistant.ToolsCallEndpointInput{
			Stream:  strm,
			Payload: params,
		}
		if _, err := endpoint(ctx, v); err != nil {
			// Send error response via SSE with proper JSON-RPC code mapping
			if req.ID != nil && req.ID != "" {
				var en goa.GoaErrorNamer
				if errors.As(err, &en) {
					switch en.GoaErrorName() {
					case "invalid_params":
						return strm.sendError(ctx, jsonrpc.IDToString(req.ID), jsonrpc.InvalidParams, goa.ErrorSafeMessage(err), jsonrpc.NewErrorData(err))
					case "method_not_found":
						return strm.sendError(ctx, jsonrpc.IDToString(req.ID), jsonrpc.MethodNotFound, goa.ErrorSafeMessage(err), jsonrpc.NewErrorData(err))
					}
				}
				// Fallback
				code := jsonrpc.InternalError
				if _, ok := err.(*goa.ServiceError); ok {
					code = jsonrpc.InvalidParams
				}
				return strm.sendError(ctx, jsonrpc.IDToString(req.ID), code, goa.ErrorSafeMessage(err), jsonrpc.NewErrorData(err))
			}
			return nil
		}
		return nil
	}
}

